/* Alert system mock.
 *
 * Alerts are derived events surfaced to customers (and potentially admin).
 * In production these would be:
 *   - Generated by ELLIS background workers (cron + event-driven)
 *   - Persisted in alerts table
 *   - Pushed via channels (in-app/email/SMS/Slack)
 *
 * For DOTBIZ prototype, we seed realistic alerts that the customer can
 * see in the Bell icon dropdown / Notifications page.
 *
 * Spec: docs/specs/dotbiz/AlertSystem.md
 */

export type AlertCategory = "Settlement" | "Booking" | "Dispute" | "Account" | "System";

export type AlertPriority = "P0" | "P1" | "P2" | "P3";

export type AlertChannel = "In-app" | "Email" | "SMS" | "Slack";

/* All alert types DOTBIZ supports */
export type AlertType =
  /* P0 — Critical (settlement) */
  | "credit_low"            /* Credit available ≤ Low threshold */
  | "credit_critical"       /* Credit ≤ Critical threshold */
  | "invoice_overdue"       /* POSTPAY invoice past due date */
  | "topup_confirmed"       /* Wire received & matched */
  | "topup_expired"         /* No wire within 7 days */
  | "topup_manual_review"   /* Wire received but ref code missing/wrong */
  /* P0 — Critical (booking) */
  | "prepay_deadline_d7" | "prepay_deadline_d3" | "prepay_deadline_d1" | "prepay_deadline_dday"
  | "booking_cancelled_by_hotel"
  | "partial_payment_detected"
  /* P1 — Important */
  | "invoice_due_soon"       /* D-2 soft reminder before POSTPAY invoice dueDate */
  | "invoice_issued"
  | "payment_received"
  | "dispute_opened"
  | "dispute_resolved"
  | "ticket_reply"
  | "checkin_tomorrow"
  | "booking_confirmed"
  | "credit_note_issued"
  /* P2 — Useful */
  | "subaccount_added"
  | "role_changed"
  | "contract_amendment"
  | "tax_filing_reminder";

export interface Alert {
  id: string;
  type: AlertType;
  category: AlertCategory;
  priority: AlertPriority;
  customerCompanyId: string;
  contractId?: string;     /* Some alerts are contract-scoped */
  title: string;
  body: string;
  /* Action link (deep link inside DOTBIZ) */
  actionLabel?: string;
  actionPath?: string;     /* e.g. /app/settlement/invoice/INV-2026-0089 */
  /* Channels that were sent */
  sentVia: AlertChannel[];
  createdAt: string;
  readAt?: string;
  dismissed?: boolean;
  /* Reference data for the source (so UI can deep-link or rerender) */
  refType?: "invoice" | "booking" | "ticket" | "contract" | "topup";
  refId?: string;
}

