/* Helper — get unread alerts for a customer */
export function unreadAlertsFor(customerCompanyId: string): Alert[] {
  return alerts.filter(a => a.customerCompanyId === customerCompanyId && !a.readAt && !a.dismissed);
}

/* Helper — get all alerts for a customer (most recent first) */
export function alertsFor(customerCompanyId: string): Alert[] {
  return alerts
    .filter(a => a.customerCompanyId === customerCompanyId && !a.dismissed)
    .sort((a, b) => b.createdAt.localeCompare(a.createdAt));
}

/* ── User preferences (per-account) ──
 * In production: stored in user_alert_preferences table.
 * For prototype: simple defaults; UI in My Account → Notifications.
 */
export interface AlertPreference {
  type: AlertType;
  enabled: boolean;
  channels: AlertChannel[];
}

